function countTableDelimiters(line: string): number {
  let previousCharIsEscapeChar = false;
  let numEscapeCharsInARow = 0;
  let numDelimiters = 0;
  let currentChar = '';
  for (let i = 0; i < line.length; i++) {
    currentChar = line[i];
